-- ── Vvveb CMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Vvveb is a free, open-source PHP content management system with a drag-and-drop page builder for building websites, blogs, and e-commerce stores.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Independent open-source project$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Vvveb CMS Review 2026: Free Open-Source Website Builder$q$, seo_title),
  seo_meta_description = COALESCE($q$Vvveb is a free, open-source PHP CMS with a drag-and-drop builder for websites, blogs, and stores. See features, pricing, and pros and cons for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Vvveb CMS is a free, open-source content management system and e-commerce platform written in PHP, created by developer 'givanz' and first published on GitHub around 2018. It is licensed under the GNU Affero General Public License v3 (AGPLv3), meaning modified versions offered as a network service must also release their source code. Vvveb combines a real-time drag-and-drop WYSIWYG page builder (also available separately as the standalone VvvebJs library) with both traditional CMS and headless CMS capabilities, exposing REST and GraphQL APIs for developers who want to build custom frontends. It supports MySQL, SQLite, and PostgreSQL databases, can run on shared hosting with minimal setup (including a zero-configuration SQLite mode), and is optimized for performance, commonly citing perfect Lighthouse scores and page-caching that approaches static-site speed. Built-in e-commerce features include product variants, subscriptions, digital product delivery, one-page checkout, coupons, and multi-currency support, positioning Vvveb as a lightweight, self-hosted alternative to WordPress plus WooCommerce, Webflow, or headless platforms like Contentful. Security features include randomizable admin login URLs, two-factor authentication, and SQL-injection protections, with an option to expose only a public folder to reduce attack surface. As a purely open-source project with no known corporate parent or funding disclosed, Vvveb has no seat-based pricing; costs are limited to self-hosting infrastructure (server, domain) rather than software licensing, appealing most to developers and small businesses who want a fast, self-hosted, no-subscription website and store builder.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '64642ef0-b3ed-44e3-9e65-2ef843fbfc7e';

