-- ── Wagtail ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Wagtail is a free, open-source content management system built on Django, originally developed by the digital agency Torchbox, known for its flexible StreamField content blocks and developer-friendly design.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Open-source project backed by Torchbox and community contributors$q$, company_size),
  headquarters = COALESCE($q$Oxford, United Kingdom (Torchbox)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and 40+ community-contributed translations$q$]::text[],
  seo_title = COALESCE($q$Wagtail CMS Review 2026: Django Content Management System$q$, seo_title),
  seo_meta_description = COALESCE($q$Wagtail is a free, open-source Django CMS with flexible StreamField content blocks. See features, history, and use cases for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wagtail is a free, open-source content management system written in Python and built on the Django web framework. It was created by Torchbox, a UK-based digital agency, starting development in late 2013/early 2014 and publicly launching the open-source project in February 2014, originally built alongside a redesign of the Royal College of Art's website. Wagtail reached its first stable 1.0 release on July 16, 2015. The project is stewarded by the Wagtail core team and a broad community of contributors, with Torchbox continuing as lead sponsor; Torchbox itself operates as an employee-owned trust focused on serving nonprofit, public-sector, and mission-driven organizations. Wagtail's signature feature is StreamField, a flexible content architecture that stores page content as structured JSON blocks (rather than rigid custom fields or plain HTML), letting editors assemble pages from reusable block types like headings, images, quotes, and custom components while developers retain full control over templates and data structure. The project has more than 17,000 stars on GitHub and is used by organizations including Google, NASA, and the NHS, among many nonprofits, universities, and media organizations. As pure open-source software released under the BSD license, Wagtail has no licensing cost; users incur only hosting and Python/Django development costs, with commercial support and custom development available from Torchbox and other Wagtail-specialist agencies. Wagtail is distinct from PHP-based CMS platforms like WordPress or TYPO3 and from other Python/Django CMS options like django CMS, appealing specifically to teams already using Django who want a highly customizable, code-first CMS rather than a plugin-driven, GUI-configured system.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'eaf343b7-68ce-48ea-8f63-afd6f23421df';

