-- ── WalkMe ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WalkMe is an enterprise digital adoption platform (DAP) that provides in-app guidance, walkthroughs, and analytics to help employees learn and use business software, now owned by SAP.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$1,500+ employees (as an SAP business unit)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (founded in Tel Aviv, Israel)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Japanese$q$, $q$Portuguese$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$WalkMe Review 2026: Digital Adoption Platform Owned by SAP$q$, seo_title),
  seo_meta_description = COALESCE($q$WalkMe is an enterprise digital adoption platform for in-app guidance and onboarding, now part of SAP. See features, pricing, and use cases for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WalkMe is an enterprise digital adoption platform (DAP) founded in 2011 in Tel Aviv, Israel by Dan Adika, Rafael Sweary, Eyal Cohen, and Yuval Shalom Ozanna. The company later moved its headquarters to San Francisco while keeping a major R&D presence in Tel Aviv. WalkMe's software overlays interactive walkthroughs, tooltips, smart tips, and automated workflows directly onto other business applications (such as Salesforce, SAP, Workday, Microsoft 365, and custom internal tools), helping employees learn software faster, reducing support tickets, and driving adoption of new systems and features. WalkMe went public on Nasdaq in 2021. On June 4, 2024, German enterprise software giant SAP announced an agreement to acquire WalkMe for approximately 1.5 billion dollars in an all-cash deal (14 dollars per share, a 45 percent premium), and the acquisition closed on September 12, 2024, after which WalkMe was delisted from Nasdaq and now operates as a business unit within SAP, complementing SAP's Business Transformation Management portfolio alongside SAP Signavio and SAP LeanIX. WalkMe's pricing has historically been enterprise-focused and quote-based, tailored to the number of end users and applications guided, rather than published self-serve tiers. WalkMe is positioned at the higher end of the digital adoption market, competing with Pendo, Whatfix, and Userlane, and is distinct from smaller product-led-growth-focused onboarding tools such as UserGuiding or Userpilot, which target SaaS product teams rather than large enterprise IT/HR software rollouts.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '76b93382-78f6-4307-a718-eb538f112980';

