-- ── wallabag ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$wallabag is a free, open-source, self-hostable read-it-later application that saves web articles in a clean, distraction-free format for offline reading, similar to Pocket.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$Independent open-source project$q$, company_size),
  headquarters = COALESCE($q$France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$, $q$Italian$q$, $q$Portuguese$q$, $q$and other community-contributed translations$q$]::text[],
  seo_title = COALESCE($q$wallabag Review 2026: Free Self-Hosted Read-It-Later App$q$, seo_title),
  seo_meta_description = COALESCE($q$wallabag is a free, open-source, self-hostable Pocket alternative for saving and reading articles later. Compare features and pricing for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$wallabag is a free and open-source read-it-later web application that lets users save online articles, strip out ads and clutter, and read them later in a clean, distraction-free view, offline or online, across devices. It was created in April 2013 by French developer Nicolas Loeuillet, originally under the name 'Poche' (French for 'pocket'), after Google Reader's shutdown prompted concerns about relying on centralized read-later services; the project was renamed wallabag after Pocket's developers sent a trademark notice regarding the original name. wallabag is released under the MIT License and is self-hostable on any server supporting PHP with MySQL, MariaDB, PostgreSQL, or SQLite as the backend, with official Docker and Podman container images available. Users can save content via browser extensions, mobile apps (Android and iOS), RSS feeds, and a public API, and can organize saved articles with tags, annotations, and full-text search; wallabag also supports importing existing libraries from Pocket, Instapaper, Pinboard, and Omnivore. For users who prefer not to self-host, the project's maintainers offer a paid managed hosting service at wallabag.it, priced around 4 euros for 3 months or roughly 11 to 30 euros per year (a higher 'supporter' tier funds further open-source development), with data hosted in Europe on Hetzner infrastructure in Germany. wallabag competes with Pocket (discontinued by Mozilla in 2025), Instapaper, and Omnivore (also discontinued), positioning itself as one of the few actively maintained, fully open-source, privacy-respecting alternatives in the read-it-later category, appealing especially to privacy-conscious users and those who want full control over their reading data.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2d0559af-047f-4b10-a092-6965237ee798';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '2d0559af-047f-4b10-a092-6965237ee798' AND logo IS NULL AND website IS NOT NULL;

